function (train_data, test_data, target_variable, nrounds = c(500),      max_depth = c(3, 6, 10, 15), eta = c(0.01, 0.05, 0.1), subsample = c(0.3,          0.5, 0.7, 0.9), colsample_bytree = c(0.3, 0.5, 0.7, 0.9),      min_child_weight = c(1, 3), gamma = c(0, 0.1), seed = 123)  {     if (!requireNamespace("xgboost", quietly = TRUE)) {         install.packages("xgboost")     }     library(xgboost)     set.seed(seed)     X_train <- train_data[, !(names(train_data) %in% target_variable),          drop = FALSE]     y_train <- train_data[[target_variable]]     x_test <- test_data[, colnames(X_train), drop = FALSE]     y_test <- test_data[[target_variable]]     X_train <- as.matrix(X_train)     x_test <- as.matrix(x_test)     y_test <- as.numeric(y_test)     y_train <- as.numeric(y_train)     dtrain <- xgb.DMatrix(data = X_train, label = y_train)     dtest <- xgb.DMatrix(data = x_test, label = y_test)     best_rmse <- Inf     best_correlation <- -Inf     best_params <- NULL     best_predictions <- NULL     best_model <- NULL     for (nrounds in nrounds) {         for (max_depth in max_depth) {             for (eta in eta) {                 for (subsample in subsample) {                   for (colsample_bytree in colsample_bytree) {                     for (min_child_weight in min_child_weight) {                       for (gamma in gamma) {                         xgb_model <- xgb.train(data = dtrain,                            eta = eta, max_depth = max_depth, subsample = subsample,                            colsample_bytree = colsample_bytree,                            min_child_weight = min_child_weight,                            gamma = gamma, nrounds = nrounds, watchlist = list(train = dtrain,                              test = dtest), verbose = 0)                         predictions <- predict(xgb_model, newdata = dtest,                            ncomp = k)                         actual_values <- as.numeric(test_data[[target_variable]])                         rmse <- sqrt(mean((actual_values - predictions)^2))                         correlation <- cor(predictions, actual_values,                            use = "complete.obs")                         if (rmse < best_rmse | (rmse == best_rmse &                            correlation > best_correlation)) {                           best_rmse <- rmse                           best_correlation <- correlation                           best_params <- list(eta = eta, max_depth = max_depth,                              subsample = subsample, colsample_bytree = colsample_bytree,                              min_child_weight = min_child_weight,                              gamma = gamma, nrounds = nrounds)                           best_predictions <- predictions                           best_model <- xgb_model                         }                       }                     }                   }                 }             }         }     }     return(list(predictions = best_predictions, RMSE = best_rmse,          correlation = best_correlation, best_params = best_params,          model = best_model)) }